        "visible_characters": [
          "田中健一",
          "石川悠一"
        ],
        "character_positions": {
          "田中健一": "画面左中偏前，坐在审讯桌一侧，脸部和嘴部清楚可见",
          "石川悠一": "画面右侧，坐在审讯桌对面，正侧脸可见，视线朝向田中健一"
        },
        "character_face_visibility": {
          "田中健一": "脸部可见，三分之二侧脸；可见五官、眼神和嘴部，眼神先低垂后抬起",
          "石川悠一": "脸部可见，正侧脸；可见五官和眼神，闭口沉默"
        },
        "key_props": [
          "INTERROGATION_TABLE_EP20",
          "CASE_FILE_AYAKA_EP20"
        ],
        "speaking_state": "田中健一为本镜头唯一主动说话人，石川悠一沉默无口型，远端声音不存在",
        "camera_motion_allowed": "固定机位，允许极轻微稳定推镜"
      },
